<template><section class="task-brief"><button class="brief-head" @click="expanded=!expanded"><span>📌 任务起点</span><span>{{ expanded?'收起 ▴':'展开 ▾' }}</span></button><div v-if="expanded" class="brief-body"><div><small>初始策略描述</small><p class="strategy">{{ strategy }}</p><p>{{ reason }}</p></div><div v-if="config.length"><small>任务配置</small><div class="config-chips"><span v-for="item in config" :key="item.key"><b>{{ item.key }}</b>{{ item.value }}</span></div></div><div v-if="factors.length"><small>初始因子任务 · {{ factors.length }}</small><div class="factor-badges"><span v-for="factor in factors" :key="factor.name">{{ factor.name }}</span></div></div></div></section></template>
<script setup lang="ts">import { computed,ref } from 'vue'; import type { FactorItem } from '../types'; const props=defineProps<{hypothesis:Record<string,unknown>|null;config:Array<{key:string;value:string}>;factors:FactorItem[]}>(); const expanded=ref(false); const strategy=computed(()=>String(props.hypothesis?.hypothesis||props.hypothesis?.concise_observation||'—')); const reason=computed(()=>String(props.hypothesis?.reason||props.hypothesis?.concise_reason||''))</script>
